use distributed_inference::pleromatic_knot_storage::KnotStorage;
use std::io;

/// Get Swarm Vibe: Retrieves the latest archived Pleromatic frame and outputs it as JSON.
/// Used by the MCP server to report swarm state to LLMs.
fn main() -> io::Result<()> {
    let storage = KnotStorage::new("assets/memory");

    match storage.latest_frame() {
        Ok(Some(frame)) => {
            println!("{}", serde_json::to_string(&frame).unwrap());
        }
        Ok(None) => {
            eprintln!("No frames found in storage.");
        }
        Err(e) => {
            eprintln!("Error reading storage: {}", e);
        }
    }

    Ok(())
}
